let executor_fee = if precompile_address == LLM_CALL_PRECOMPILE { ... }
    else if precompile_address == HTTP_CALL_PRECOMPILE { http_executor_fee(input_len, HTTP_CALL_MAX_OUTPUT_BYTES) }
    else if precompile_address == LONG_RUNNING_HTTP_PRECOMPILE { http_executor_fee(input_len, HTTP_CALL_MAX_OUTPUT_BYTES) }
    else if precompile_address == SOVEREIGN_AGENT_PRECOMPILE { agent_escrow_lockup(...) }
    else if precompile_address == ZK_TWO_PHASE_PRECOMPILE { U256::from(ZK_PROOF_GENERATION_FEE_WEI) }
    else if precompile_address == IMAGE_CALL_PRECOMPILE { ... }
    else if precompile_address == AUDIO_CALL_PRECOMPILE { ... }
    else if precompile_address == VIDEO_CALL_PRECOMPILE { ... }
    else if precompile_address == FHE_PRECOMPILE { fhe_escrow_lockup() }
    else if precompile_address == DKMS_KEY_PRECOMPILE { dkms_escrow_lockup(input_len) }
    else if precompile_address == PERSISTENT_AGENT_PRECOMPILE { persistent_agent_escrow_lockup(input_len) }
    else { return Err(format!("Unknown precompile address for wallet verification: {:?}", precompile_address)); };

let commitment_fee = async_commitment_fee(input_len);
let inclusion_fee = async_inclusion_fee(input_len, HTTP_CALL_MAX_OUTPUT_BYTES);

let phase2_callback_cost = if precompile_address == LONG_RUNNING_HTTP_PRECOMPILE { DeliveryConfig::from_abi(precompile_input)? ... }
    else if precompile_address == IMAGE_CALL_PRECOMPILE { DeliveryConfig::from_abi(precompile_input)? ... }
    else if precompile_address == AUDIO_CALL_PRECOMPILE { DeliveryConfig::from_abi(precompile_input)? ... }
    else if precompile_address == VIDEO_CALL_PRECOMPILE { DeliveryConfig::from_abi(precompile_input)? ... }
    else if precompile_address == ZK_TWO_PHASE_PRECOMPILE { DeliveryConfig::from_zk_abi(precompile_input)? ... }
    else if precompile_address == SOVEREIGN_AGENT_PRECOMPILE { DeliveryConfig::from_sovereign_agent_abi(precompile_input)? ... }
    else if precompile_address == FHE_PRECOMPILE { DeliveryConfig::from_fhe_abi(precompile_input)? ... }
    else if precompile_address == PERSISTENT_AGENT_PRECOMPILE { DeliveryConfig::from_persistent_agent_abi(precompile_input)? ... }
    else if is_two_phase_precompile(precompile_address) { return Err(...); }
    else { U256::ZERO };

let total_required_fees = executor_fee + commitment_fee + inclusion_fee + phase2_callback_cost;
let required_lock_until = commit_block + ttl;

if balance < total_required_fees { return Err(format!("Insufficient wallet balance: {} < required {} (user: {:?})", ...)); }

if lock_until < U256::from(required_lock_until) { return Err(format!("Insufficient lock duration: {} < required {} (commit_block {} + ttl {}, user: {:?})", ...)); }

Ok(())

pub fn extract_commitment_sender(original_tx: &OriginalTransaction) -> Result<Address, String> {
    match original_tx {
        OriginalTransaction::Scheduled(signed) => Ok(signed.tx().caller),
        OriginalTransaction::Legacy(signed) => { ... recover_signer() ... }
        OriginalTransaction::Eip1559(signed) => { ... recover_signer() ... }
        OriginalTransaction::Passkey(signed) => { ... recover_signer() ... }
        OriginalTransaction::AsyncSettlement(signed) => Ok(signed.tx().user_address),
    }
}
